// // This module implements a 5-bit Johnson counter with an active low synchronous reset. The counter shifts left by one bit on each positive clock edge and the rightmost bit is the inverted value of the leftmost bit.
module top_module(
	input clk,
	input reset,
	output reg [4:0] count);always @(posedge clk)
	if (reset)
		count <= 5'b00000;
	else
		count <= {~count[0], count[4:1]};

endmodule
